class Solution:
    def minSwaps(self, nums: List[int]) -> int:
        ones = nums.count(1)
        res = 0
        left = 0
        for right in range(len(nums)):
            if nums[right] == 1:
                left += 1
            while left > ones:
                if nums[left % len(nums)] == 1:
                    left += 1
                else:
                    left = (left + 1) % len(nums)
            res = max(res, right - left + 1)
        return res
